To create a Discord bot using Discord.js v14 with a slash command for banning users, you'll need to follow these steps:

1. First, make sure you have Node.js installed. You can download it from https://nodejs.org/en/download/.

2. Create a new directory for your bot and navigate to it in your terminal.

3. Run `npm init` to create a `package.json` file and follow the prompts.

4. Install Discord.js and the types for it:

```
npm install discord.js
npm install @discordjs/build-tools
```

5. Create a new file called `index.js`.

6. Paste the following code into `index.js` and replace `YOUR_APP_ID` and `YOUR_TOKEN` with your bot's application ID and token respectively.

```javascript
const { Client, Intents, Collection } = require('discord.js');
const { REST } = require('@discordjs/rest');
const { Routes } = require('discord-api-types/v10');

const client = new Client({ intents: [Intents.Guilds, Intents.GuildMembers, Intents.GuildMessages] });

client.commands = new Collection();

const commands = [
  {
    name: 'ban',
    description: 'Bans a user',
    options: [
      {
        name: 'user',
        description: 'The user to ban',
        type: 6, // User
        required: true
      },
      {
        name: 'days',
        description: 'The number of days the ban lasts (optional)',
        type: 4, // Number
        required: false
      }
    ]
  }
];

for (const command of commands) {
  client.commands.set(command.name, command);
}

client.on('ready', () => {
  console.log(`Bot is ready as ${client.user.tag}`);
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const command = client.commands.get(interaction.commandName);

  if (!command) return;

  try {
    command.execute(interaction);
  } catch (error) {
    console.error(error);
    await interaction.reply({ content: 'There was an error while executing this command!', ephemeral: true });
  }
});

const rest = new REST({ version: '10' }).setToken(process.env.TOKEN);

(async () => {
  try {
    console.log('Started refreshing application (/) commands.');

    await rest.put(
      Routes.applicationGuildCommands(process.env.CLIENT_ID, process.env.GUILD_ID),
      { body: commands.map(command => command) }
    );

    console.log('Successfully reloaded application (/) commands.');
  } catch (error) {
    console.error(error);
  }
})();

client.login(process.env.TOKEN);
```

7. Create a `.env` file in the same directory as `index.js`.

8. Add your bot's token and guild ID in the `.env` file:

```
TOKEN=YOUR_TOKEN
GUILD_ID=YOUR_GUILD_ID
```

9. To use the `dotenv` package, run `npm install dotenv`.

10. Update the `index.js` file to require and use `dotenv`:

```javascript
const { Client, Intents, Collection } = require('discord.js');
const { REST } = require('@discordjs/rest');
const { Routes } = require('discord-api-types/v10');
require('dotenv').config();
```

11. Now, create the `ban` command function that will be called when the slash command is used:

```javascript
client.on('interactionCreate', async interaction => {
  // ...

  const command = client.commands.get(interaction.commandName);

  if (command) {
    command.execute(interaction);
  } else {
    await interaction.reply({ content: 'Unknown command.', ephemeral: true });
  }
});

const banCommand = {
  name: 'ban',
  execute(interaction) {
    const member = interaction.guild.members.cache.get(interaction.options.getUser('user').id);
    const days = interaction.options.getNumber('days') || 0;

    member.ban({ days });

    interaction.reply({ content: `Successfully banned ${member.user.tag} for ${days} days.`, ephemeral: true });
  }
};
```

Make sure to replace `YOUR_APP_ID`, `YOUR_TOKEN`, and `YOUR_GUILD_ID` with the correct values.

12. Run the bot with `node index.js`.

Remember that this bot requires your bot to have the necessary permissions for banning users in the server. You can manage bot permissions using the Discord developer portal.

For more information about slash commands, visit the official Discord.js documentation: https://discordjs.guide/creating-your-bot/slash-commands.html

To convert Markdown to HTML, you can use a library like `boost::property_tree` or `cppmarkdownlite`. However, for a simple and basic conversion, here's a code snippet that uses `std::regex` to perform some common Markdown to HTML conversions:

```cpp
#include <regex>
#include <string>
#include <iostream>

std::string markdownToHtml(const std::string &md) {
    std::string html;
    std::regex headingRegex(R"(^#+\s(.*))");
    std::smatch match;
    std::regex_iterator<std::string::const_iterator> begin(md.cbegin(), md.cend()), end;

    while (std::regex_search(md.cbegin(), md.cend(), match, headingRegex)) {
        int level = match.str(0).length() - 1;
        std::string content = match.str(1);
        html += "<h" + std::to_string(level) + ">" + content + "</h" + std::to_string(level) + ">\n";
        md.erase(match.first, match.second);
    }

    std::regex linkRegex(R"((\[.*\])(?:\(.*\)))");
    std::regex_iterator<std::string::const_iterator> linkBegin(md.cbegin(), md.cend(), linkRegex);
    std::regex_iterator<std::string::const_iterator> linkEnd;
    while (linkBegin != linkEnd) {
        std::smatch linkMatch = *linkBegin;
        std::string linkText = linkMatch.str(1);
        std::string linkUrl = linkMatch.str(2).substr(1, linkMatch.str(2).length() - 2);
        html += "<a href=\"" + linkUrl + "\">" + linkText + "</a>";
        md.erase(linkBegin->first, linkMatch.second);
        linkBegin++;
    }

    std::regex italicRegex(R"(\*([^*]*)\*)");
    std::regex_iterator<std::string::const_iterator> italicBegin(md.cbegin(), md.cend(), italicRegex);
    std::regex_iterator<std::string::const_iterator> italicEnd;
    while (italicBegin != italicEnd) {
        std::smatch italicMatch = *italicBegin;
        html += "<em>" + italicMatch.str(1) + "</em>";
        md.erase(italicBegin->first, italicMatch.second);
        italicBegin++;
    }

    std::regex boldRegex(R"(\*\*([^*]*)\*\*)");
    std::regex_iterator<std::string::const_iterator> boldBegin(md.cbegin(), md.cend(), boldRegex);
    std::regex_iterator<std::string::const_iterator> boldEnd;
    while (boldBegin != boldEnd) {
        std::smatch boldMatch = *boldBegin;
        html += "<strong>" + boldMatch.str(1) + "</strong>";
        md.erase(boldBegin->first, boldMatch.second);
        boldBegin++;
    }

    html += md;
    return html;
}

int main() {
    std::string markdown = "# Heading\n\n**Bold Text**\n\n[Link Text](http://example.com)\n\n*Italic Text*\n";
    std::string html = markdownToHtml(markdown);
    std::cout << html << std::endl;
    return 0;
}
```

This code handles simple Markdown formatting like headings, bold, italic, and links. For more complex Markdown features, you might want to use a library like `cppmarkdownlite`.

